-- ================================================================
-- SEED — catálogo real de claves presupuestales (SESESP)
-- Fuente: Catalogo Claves Presupuestales.csv (133 registros)
-- Se ejecuta una sola vez, junto con 01-schema.sql y 02-seed-catalogos.sql,
-- cuando el volumen de MySQL está vacío (docker-entrypoint-initdb.d).
--
-- FOREIGN_KEY_CHECKS se desactiva porque este script corre ANTES de que
-- el backend arranque y cree el usuario SISTEMA (id_usuario=1, ver
-- DataInitializer.crearUsuarioSistema) al que usuario_creacion hace
-- referencia — mismo patrón que 02-seed-catalogos.sql.
-- ================================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

START TRANSACTION;


COMMIT;

SET FOREIGN_KEY_CHECKS = 1;
